const dados = $input.all().map(item => item.json);
const fontesFiltradas = ["IDEIAS", "RSS"];
const dadosFiltrados = dados.filter(item =>
  fontesFiltradas.includes((item.fonte || "").trim().toUpperCase())
);

function filtrarPorSemanaAtual(dados) {
  const hoje = new Date();
  const inicioSemana = new Date(hoje);
  inicioSemana.setDate(hoje.getDate() - hoje.getDay());
  inicioSemana.setHours(0, 0, 0, 0);
  const fimSemana = new Date(inicioSemana);
  fimSemana.setDate(inicioSemana.getDate() + 7);

  return dados.filter((item) => {
    const dataStr = item.data_criacao;
    if (!dataStr) return false;
    const [dataParte, horaParte] = dataStr.split(" ");
    const [dia, mes, ano] = dataParte.split("/");
    const [hora, minuto] = horaParte.split(":");
    const data = new Date(ano, mes - 1, dia, hora, minuto);
    const dentroSemana = data >= inicioSemana && data < fimSemana;

    // Apenas instagram e whatsapp devem estar postados
    const statusObrigatorios = ["status_instagram", "status_whatsapp"];
    const todosPostados = statusObrigatorios.every(key =>
      (item[key] || "").trim().toLowerCase() === "postado"
    );

    return dentroSemana && todosPostados;
  });
}

const filtrados = filtrarPorSemanaAtual(dadosFiltrados);

const posts_da_semana = filtrados.map(item => {
  return {
    data_criacao: item.data_criacao,
    legenda_instagram: item.legenda_instagram,
    legenda_whatsapp: item.legenda_whatsapp
  };
});

return [{ json: { posts_da_semana } }];

