const fixo = $items("Pega dados fixos do cliente")[0].json;

function parseCfg(str){
  try { return JSON.parse(str); } catch { return null; }
}

// Data e hora atual em São Paulo
const agora = new Date().toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo' });
const [dataParte, horaParte] = agora.split(', ');
const [dia, mes, ano] = dataParte.split('/');
const [horas, minutos] = horaParte.split(':');
const horarioAtual = `${dia.padStart(2,'0')}/${mes.padStart(2,'0')}/${ano} ${horas.padStart(2,'0')}:${minutos.padStart(2,'0')}`;

// Pega plataformas ativas
const plataformas = Object.keys(fixo)
  .filter(k => k.startsWith("config_postagem_"))
  .map(k => k.replace("config_postagem_", ""));

const retorno = {};

for(const p of plataformas){
  const cfg = parseCfg(fixo[`config_postagem_${p}`]);
  if(!cfg || !cfg.ativo){
    retorno[`horario_post_${p}`] = "-";
    continue;
  }
  retorno[`horario_post_${p}`] = horarioAtual;
}

return [{ json: retorno }];

